@page "/apply"
@using sv_fb922971976e491aafd08a2f2388d0eb.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="step-indicator mb-4">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var stepIndex = i;
            var status = stepIndex < _currentStep ? "completed"
                       : stepIndex == _currentStep ? "active"
                       : "upcoming";
            <button class="step-item @status"
                    disabled="@(status == "upcoming")"
                    @onclick="() => GoToStep(stepIndex)">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </span>
                <span class="step-label">@_stepLabels[stepIndex]</span>
            </button>
            @if (stepIndex < _stepLabels.Length - 1)
            {
                <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (_currentStep == 0)
    {
        <div class="step-content">
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="_fullName" @bind:event="oninput" placeholder="Jane Doe" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="_email" @bind:event="oninput" placeholder="jane@example.com" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" placeholder="(555) 123-4567" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
            </div>
            <div class="step-buttons">
                <div></div>
                <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                    @if (_isValidating)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <span>Validating…</span>
                    }
                    else
                    {
                        <span>Next</span>
                    }
                </button>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (_currentStep == 1)
    {
        <div class="step-content">
            <h4>Work History</h4>
            @for (int i = 0; i < _workEntries.Count; i++)
            {
                var idx = i;
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_workEntries[idx].Company"
                                       @onchange="(e) => UpdateWork(idx, w => w.Company = e.Value?.ToString() ?? "")" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_workEntries[idx].Title"
                                       @onchange="(e) => UpdateWork(idx, w => w.Title = e.Value?.ToString() ?? "")" />
                            </div>
                        </div>
                        <div class="row mb-2">
