                @* Work History *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate?.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small class="text-muted">@r.Email &middot; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <p style="white-space:pre-wrap;">@_coverLetter</p>
                </div>

                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                        @if (_isSubmitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Submitting…</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                </div>
            }
        </div>
    }
</div>

@code {
    private static readonly string[] _stepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private string _errorMessage = "";

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";
    private bool _isValidating;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = "";

    // Step 5
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // ── Navigation ──

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _errorMessage = "";
            _currentStep = step;
        }
    }

    private void PreviousStep()
    {
        _errorMessage = "";
        if (_currentStep > 0) _currentStep--;
    }

    // ── Step 1 Validation ──

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = "";
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
            _currentStep = 1;
        }
        finally
        {
            _isValidating = false;
        }
    }

    // ── Step 2 ──

    private void AddWorkEntry() => _workEntries.Add(new());

    private void RemoveWorkEntry(int idx)
    {
        if (_workEntries.Count > 1)
            _workEntries.RemoveAt(idx);
    }

    private void UpdateWork(int idx, Action<WorkEntryModel> update)
    {
        update(_workEntries[idx]);
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = "";
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate is null)
            {
                _errorMessage = "Each position requires a company, title, and start date.";
                return;
            }
        }
        _currentStep = 2;
    }

    // ── Step 3 ──

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new());
    }

    private void RemoveReference(int idx)
    {
        if (_references.Count > 2) _references.RemoveAt(idx);
    }

    private void UpdateRef(int idx, Action<ReferenceModel> update)
    {
        update(_references[idx]);
    }

    private void NextFromReferences()
    {
        _errorMessage = "";
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        _currentStep = 3;
    }

    // ── Step 4 ──

    private void NextFromCoverLetter()
    {
        _errorMessage = "";
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please write a cover letter.";
            return;
        }
        _currentStep = 4;
    }

    // ── Step 5 ──

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = "";
        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workEntries = _workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.EndDate, e.Description)).ToList();
            var refs = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, new WorkHistory(workEntries), refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    // ── Mutable models for form binding ──

    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

.apply-container {
