/* ── Step Indicator ── */

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
    min-width: 90px;
    transition: opacity 0.2s;
}

    .step-item:disabled {
        cursor: default;
    }

    .step-item.upcoming {
        opacity: 0.4;
    }

    .step-item.active .step-circle {
        background: #0d6efd;
        color: #fff;
        font-weight: bold;
    }

    .step-item.completed .step-circle {
        background: #198754;
        color: #fff;
    }

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.9rem;
