                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_references[idx].Name"
                                       @onchange="(e) => UpdateRef(idx, r => r.Name = e.Value?.ToString() ?? "")" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_references[idx].Relationship"
                                       @onchange="(e) => UpdateRef(idx, r => r.Relationship = e.Value?.ToString() ?? "")" />
                            </div>
