{"file_text": ".apply-container {
    max-width: 800px;
    margin: 0 auto;
}

/* ── Step Indicator ── */

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
    min-width: 90px;
    transition: opacity 0.2s;
}

    .step-item:disabled {
        cursor: default;
    }

    .step-item.upcoming {
        opacity: 0.4;
    }

    .step-item.active .step-circle {
        background: #0d6efd;
        color: #fff;
        font-weight: bold;
    }

    .step-item.completed .step-circle {
        background: #198754;
        color: #fff;
    }

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    margin-bottom: 0.25rem;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #495057;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    min-width: 20px;
    align-self: center;
    margin-bottom: 1.2rem;
    transition: background 0.2s;
}

    .step-connector.completed {
        background: #198754;
    }

/* ── Step Content ── */

.step-content {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.5rem;
}

.step-buttons {
    display: flex;
    justify-content: space-between;
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid #eee;
}

/* ── Review Section ── */

.review-section {
    border: 1px solid #eee;
    border-radius: 0.375rem;
    padding: 1rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

    .review-section h5 {
        margin-bottom: 0.5rem;
        font-size: 1rem;
    }
