@page "/apply"
@using sv_fb922971976e491aafd08a2f2388d0eb.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="step-indicator mb-4">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var stepIndex = i;
            var status = stepIndex < _currentStep ? "completed"
                       : stepIndex == _currentStep ? "active"
                       : "upcoming";
            <button class="step-item @status"
                    disabled="@(status == "upcoming")"
                    @onclick="() => GoToStep(stepIndex)">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </span>
                <span class="step-label">@_stepLabels[stepIndex]</span>
            </button>
            @if (stepIndex < _stepLabels.Length - 1)
            {
                <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (_currentStep == 0)
    {
        <div class="step-content">
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="_fullName" @bind:event="oninput" placeholder="Jane Doe" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="_email" @bind:event="oninput" placeholder="jane@example.com" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" placeholder="(555) 123-4567" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
            </div>
            <div class="step-buttons">
                <div></div>
                <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                    @if (_isValidating)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <span>Validating…</span>
                    }
                    else
                    {
                        <span>Next</span>
                    }
                </button>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (_currentStep == 1)
    {
        <div class="step-content">
            <h4>Work History</h4>
            @for (int i = 0; i < _workEntries.Count; i++)
            {
                var idx = i;
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_workEntries[idx].Company"
                                       @onchange="(e) => UpdateWork(idx, w => w.Company = e.Value?.ToString() ?? "")" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_workEntries[idx].Title"
                                       @onchange="(e) => UpdateWork(idx, w => w.Title = e.Value?.ToString() ?? "")" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" value="@_workEntries[idx].StartDate?.ToString("yyyy-MM-dd")"
                                       @onchange="(e) => UpdateWork(idx, w => w.StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" value="@_workEntries[idx].EndDate?.ToString("yyyy-MM-dd")"
                                       disabled="@_workEntries[idx].IsCurrent"
                                       @onchange="(e) => UpdateWork(idx, w => w.EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end mb-1">
                                <div class="form-check">
                                    <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                           checked="@_workEntries[idx].IsCurrent"
                                           @onchange="(e) => UpdateWork(idx, w => { w.IsCurrent = (bool)(e.Value ?? false); if (w.IsCurrent) w.EndDate = null; })" />
                                    <label class="form-check-label" for="@($"current-{idx}")">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" rows="2" value="@_workEntries[idx].Description"
                                      @onchange="(e) => UpdateWork(idx, w => w.Description = e.Value?.ToString() ?? "")"></textarea>
                        </div>
                    </div>
                </div>
            }
            <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                &#43; Add Another Position
            </button>
            <div class="step-buttons">
                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
            </div>
        </div>
    }

    @* ───── Step 3: References ───── *@
    @if (_currentStep == 2)
    {
        <div class="step-content">
            <h4>References</h4>
            @for (int i = 0; i < _references.Count; i++)
            {
                var idx = i;
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (_references.Count > 2)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_references[idx].Name"
                                       @onchange="(e) => UpdateRef(idx, r => r.Name = e.Value?.ToString() ?? "")" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@_references[idx].Relationship"
                                       @onchange="(e) => UpdateRef(idx, r => r.Relationship = e.Value?.ToString() ?? "")" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" value="@_references[idx].Email"
                                       @onchange="(e) => UpdateRef(idx, r => r.Email = e.Value?.ToString() ?? "")" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" value="@_references[idx].Phone"
                                       @onchange="(e) => UpdateRef(idx, r => r.Phone = e.Value?.ToString() ?? "")" />
                            </div>
                        </div>
                    </div>
                </div>
            }
            @if (_references.Count < 3)
            {
                <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                    &#43; Add Reference
                </button>
            }
            <div class="step-buttons">
                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
            </div>
        </div>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (_currentStep == 3)
    {
        <div class="step-content">
            <h4>Cover Letter</h4>
            <div class="mb-2">
                <textarea class="form-control" rows="10" @bind="_coverLetter" @bind:event="oninput"
                          maxlength="2000" placeholder="Tell us why you're a great fit…"></textarea>
            </div>
            <div class="text-muted mb-3">@_coverLetter.Length / 2000 characters</div>
            <div class="step-buttons">
                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
            </div>
        </div>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (_currentStep == 4)
    {
        <div class="step-content">
            @if (_submitted)
            {
                <div class="text-center py-5">
                    <div class="mb-3" style="font-size:3rem;">&#10003;</div>
                    <h4 class="text-success">Application Submitted!</h4>
                    <p>Your application ID is <strong>@_applicationId</strong>.</p>
                    <p class="text-muted">We'll be in touch soon.</p>
                </div>
            }
            else
            {
                <h4>Review &amp; Submit</h4>

                @* Personal Info *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Personal Information</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(0)">Edit</button>
                    </div>
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>

                @* Work History *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate?.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small class="text-muted">@r.Email &middot; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter *@
                <div class="review-section">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <p style="white-space:pre-wrap;">@_coverLetter</p>
                </div>

                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                        @if (_isSubmitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Submitting…</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                </div>
            }
        </div>
    }
</div>

